let transactions = List([])
let balance = Obs(0)
let income = Obs(0)
let expense = Obs(0)
fn addTransaction(title, amount, isExpense) {
  let t = {
    id: now(),
    title: title,
    amount: toDouble(amount),
    isExpense: isExpense,
    date: now()
  }
  transactions.add(t)
  calculateBalance()
}
fn calculateBalance() {
  let total = 0
  let inc = 0
  let exp = 0
  transactions.forEach(fn(t) {
    if (t.isExpense) {
      total = total - t.amount
      exp = exp + t.amount
    } else {
      total = total + t.amount
      inc = inc + t.amount
    }
  })
  balance.set(0)
  income.set(0)
  expense.set(0)
}
