fn formatDate(date) {
  if (date > 1000000000000) {
    let currentTime = now()
    let diff = currentTime - date
    let days = toInt(diff / 86400000)
    if (days == 0) {
      return "Aujourd'hui"
    }
    if (days == 1) {
      return "Hier"
    }
    if (days < 7) {
      return days + " jours"
    }
    return "Il y a " + toInt(days / 7) + " sem."
  }
  return date
}
