  return Text("+" + income.value + " €", { color: "white", fontSize: 18, fontWeight: "bold" })
}
fn expenseDisplay() {
  return Text("-" + expense.value + " €", { color: "white", fontSize: 18, fontWeight: "bold" })
}
fn transactionList() {
  if (transactions.value.length == 0) {
    return Center(Column({ spacing: 8, crossAxisAlignment: "center" }, [Icon("receipt_long", { size: 48, color: "grey", opacity: 0.5 }), Text("Aucune transaction", { color: "grey", fontSize: 16 })]))
  }
  return Column({ spacing: 8 }, transactions.value.map(fn(t) {
    let iconName = "arrow_upward"
    let bgColor = Theme.success + "20"
    let textColor = Theme.success
    let prefix = "+"
    if (t.isExpense) {
      iconName = "arrow_downward"
      bgColor = Theme.danger + "20"
      textColor = Theme.danger
      prefix = "-"
    }
    return ListTile({
      leading: Box({
        width: 40,
        height: 40,
        borderRadius: 20,
        color: bgColor,
        alignment: "center"
      }, Icon(iconName, { size: 20, color: textColor })),
      title: Text(t.title, { fontWeight: "bold", fontSize: 16 }),
      subtitle: Text(formatDate(t.date), { color: "grey", fontSize: 12 }),
      trailing: Text(prefix + t.amount + " €", { color: textColor, fontWeight: "bold", fontSize: 16 }),
      onTap: "onTransactionTap"
    })
  }))
}
fn onRefresh() {
  ui.toast("Actualisation des données...")
  calculateBalance()
  delayed(1000, fn() {
    ui.toast("Données actualisées !")
  })
}
fn goToAdd() {
  ui.push("add_transaction")
}
fn goToStats() {
  ui.push("stats")
}
fn goToTransactions() {
  ui.push("transactions")
}
fn onTransactionTap() {
  ui.toast("Détails de la transaction")
}

