let title = Obs("")
let amount = Obs("")
let isExpense = Obs(true)
fn build() {
  return Scaffold({ appBar: AppBar({ title: "Nouvelle Transaction", backgroundColor: Theme.primary }), body: Column({ padding: 16, spacing: 20 }, [Obx({ builder: "typeSelector" }), TextField({ labelText: "Titre", placeholder: "Ex: Courses, Loyer...", onChange: "setTitle" }), TextField({ labelText: "Montant (€)", keyboardType: "number", onChange: "setAmount" }), Button("Enregistrer", {
