fn typeSelector() {
  let expenseColor = "grey"
  if (isExpense.value) {
    expenseColor = Theme.danger
  }
  let incomeColor = "grey"
  if (!isExpense.value) {
    incomeColor = Theme.success
  }
  return Row({ spacing: 10 }, [Button("Dépense", { color: expenseColor, onTap: "setExpense", flex: 1 }), Button("Revenu", { color: incomeColor, onTap: "setIncome", flex: 1 })])
}
fn setExpense() {
  isExpense.set(true)
}
fn setIncome() {
  isExpense.set(false)
}
fn setTitle(val) {
  title.set(val)
}
fn setAmount(val) {
  amount.set(val)
}
fn saveTransaction() {
  if (title.value == "" || amount.value == "") {
    ui.toast("Veuillez remplir tous les champs")
    return
  }
  addTransaction(title.value, amount.value, isExpense.value)
  ui.pop()
}

